def _apply_premium_discount(subtotal, premium=False):
    if premium:
        subtotal = subtotal - subtotal * 0.1
    return round(subtotal, 2)


def invoice_total(subtotal, premium=False):
    return _apply_premium_discount(subtotal, premium)


def renewal_total(subtotal, premium=False):
    return _apply_premium_discount(subtotal, premium)

