import json
from pathlib import Path

STATE_FILE = Path('tasks.json')


def save_task(task):
    tasks = load_tasks()
    tasks.append(task)
    STATE_FILE.write_text(json.dumps(tasks), encoding='utf-8')


def load_tasks():
    if not STATE_FILE.exists():
        return []
    return json.loads(STATE_FILE.read_text(encoding='utf-8'))
